from __future__ import annotations

from datetime import datetime, timedelta, timezone
from hashlib import sha256

from fastapi import FastAPI, HTTPException, Depends
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel

app = FastAPI(title="Auth API")
security = HTTPBearer()
USERS: dict[str, dict] = {}
SECRET = "dev-secret-key"


def _hash(password: str) -> str:
    return sha256((password + SECRET).encode()).hexdigest()


def _create_token(email: str) -> str:
    exp = (datetime.now(timezone.utc) + timedelta(hours=24)).isoformat()
    return sha256(f"{email}:{exp}:{SECRET}".encode()).hexdigest()


class UserRegister(BaseModel):
    email: str
    password: str
    name: str


@app.post("/register", status_code=201)
async def register(user: UserRegister) -> dict:
    if user.email in USERS:
        raise HTTPException(status_code=409, detail="Already registered")
    USERS[user.email] = {"email": user.email, "name": user.name, "pw": _hash(user.password)}
    return {"message": "OK", "email": user.email}


@app.post("/login")
async def login(email: str, password: str) -> dict:
    user = USERS.get(email)
    if not user or user["pw"] != _hash(password):
        raise HTTPException(status_code=401, detail="Invalid credentials")
    return {"token": _create_token(email), "type": "bearer"}


@app.get("/me")
async def me(cred: HTTPAuthorizationCredentials = Depends(security)) -> dict:
    return {"token": cred.credentials[:8] + "..."}

from __future__ import annotations

from fastapi import FastAPI, WebSocket, WebSocketDisconnect

app = FastAPI()


class ConnectionManager:
    def __init__(self) -> None:
        self.active: list[WebSocket] = []

    async def connect(self, ws: WebSocket) -> None:
        await ws.accept()
        self.active.append(ws)

    def disconnect(self, ws: WebSocket) -> None:
        self.active.remove(ws)

    async def broadcast(self, message: str, exclude: WebSocket | None = None) -> None:
        for conn in self.active:
            if conn is not exclude:
                await conn.send_text(message)


manager = ConnectionManager()


@app.websocket("/ws/{username}")
async def chat(websocket: WebSocket, username: str) -> None:
    await manager.connect(websocket)
    await manager.broadcast(f"{username} joined")
    try:
        while True:
            data = await websocket.receive_text()
            await manager.broadcast(f"{username}: {data}", exclude=websocket)
    except WebSocketDisconnect:
        manager.disconnect(websocket)
        await manager.broadcast(f"{username} left")

from __future__ import annotations

import argparse


def c_to_f(c: float) -> float:
    return c * 9 / 5 + 32

def f_to_c(f: float) -> float:
    return (f - 32) * 5 / 9

def c_to_k(c: float) -> float:
    return c + 273.15

def k_to_c(k: float) -> float:
    return k - 273.15


def main() -> int:
    parser = argparse.ArgumentParser(description="Temperature converter")
    parser.add_argument("value", type=float)
    parser.add_argument("from_unit", choices=["C", "F", "K"])
    parser.add_argument("to_unit", choices=["C", "F", "K"])
    args = parser.parse_args()

    if args.from_unit == args.to_unit:
        print(f"{args.value:.2f} {args.to_unit}")
        return 0

    if args.from_unit == "F":
        c = f_to_c(args.value)
    elif args.from_unit == "K":
        c = k_to_c(args.value)
    else:
        c = args.value

    if args.to_unit == "F":
        result = c_to_f(c)
    elif args.to_unit == "K":
        result = c_to_k(c)
    else:
        result = c

    print(f"{result:.2f} {args.to_unit}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

from __future__ import annotations

import shutil
import sys
from pathlib import Path

EXT_MAP = {".py": "python", ".js": "js", ".ts": "ts", ".md": "docs",
           ".txt": "docs", ".json": "data", ".png": "images", ".jpg": "images"}


def organize(directory: Path, dry_run: bool = False) -> dict[str, int]:
    counts: dict[str, int] = {}
    for f in directory.iterdir():
        if f.is_dir():
            continue
        folder = EXT_MAP.get(f.suffix.lower(), "other")
        counts[folder] = counts.get(folder, 0) + 1
        dest = directory / folder
        if not dry_run:
            dest.mkdir(exist_ok=True)
            shutil.move(str(f), str(dest / f.name))
    return counts


def main() -> int:
    import argparse
    parser = argparse.ArgumentParser(description="Organize files by extension")
    parser.add_argument("directory")
    parser.add_argument("--dry-run", action="store_true")
    args = parser.parse_args()
    target = Path(args.directory)
    if not target.is_dir():
        print(f"Error: {target} is not a directory", file=sys.stderr)
        return 1
    for folder, count in organize(target, args.dry_run).items():
        print(f"  {'Would move' if args.dry_run else 'Moved'} {count} -> {folder}/")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

from __future__ import annotations

import json
import time
import urllib.request
import urllib.error
from typing import Any


class ApiClient:
    def __init__(self, base_url: str, timeout: int = 10, retries: int = 3) -> None:
        self.base_url = base_url.rstrip("/")
        self.timeout = timeout
        self.retries = retries

    def _request(self, method: str, path: str, data: dict | None = None) -> dict[str, Any]:
        url = f"{self.base_url}{path}"
        body = json.dumps(data).encode() if data else None
        headers = {"Content-Type": "application/json"} if data else {}
        for attempt in range(1, self.retries + 1):
            try:
                req = urllib.request.Request(url, data=body, headers=headers, method=method)
                with urllib.request.urlopen(req, timeout=self.timeout) as resp:
                    return json.loads(resp.read().decode())
            except urllib.error.HTTPError as exc:
                if exc.code >= 500 and attempt < self.retries:
                    time.sleep(attempt * 0.5)
                    continue
                raise
        return {}

    def get(self, path: str) -> dict[str, Any]:
        return self._request("GET", path)

    def post(self, path: str, data: dict) -> dict[str, Any]:
        return self._request("POST", path, data)

from __future__ import annotations

import threading
import time
from typing import Any, Callable


class TaskScheduler:
    def __init__(self) -> None:
        self._tasks: list[tuple[Callable, float, threading.Event]] = []
        self._running = True

    def schedule(self, func: Callable, interval_seconds: float) -> None:
        stop_event = threading.Event()
        self._tasks.append((func, interval_seconds, stop_event))

        def runner() -> None:
            while self._running and not stop_event.is_set():
                func()
                stop_event.wait(interval_seconds)

        t = threading.Thread(target=runner, daemon=True)
        t.start()

    def shutdown(self) -> None:
        self._running = False
        for _, _, event in self._tasks:
            event.set()


def demo_job() -> None:
    print(f"Job executed at {time.strftime('%H:%M:%S')}")


if __name__ == "__main__":
    scheduler = TaskScheduler()
    scheduler.schedule(demo_job, interval_seconds=2)
    try:
        time.sleep(10)
    except KeyboardInterrupt:
        pass
    finally:
        scheduler.shutdown()

import React, { useState } from "react";

interface Todo { id: number; text: string; done: boolean }

export default function TodoList() {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [input, setInput] = useState("");

  const add = () => {
    if (!input.trim()) return;
    setTodos(prev => [...prev, { id: Date.now(), text: input.trim(), done: false }]);
    setInput("");
  };

  return (
    <div>
      <h1>Todos</h1>
      <form onSubmit={e => { e.preventDefault(); add(); }}>
        <input value={input} onChange={e => setInput(e.target.value)} placeholder="Add..." />
        <button type="submit">Add</button>
      </form>
      <ul>
        {todos.map(t => (
          <li key={t.id}>
