              {t.text}
            </span>
            <button onClick={() => setTodos(prev => prev.filter(x => x.id !== t.id))}>Delete</button>
          </li>
        ))}
      </ul>
      <p>{todos.filter(t => !t.done).length} remaining</p>
    </div>
  );
}

