import React, { useCallback, useEffect, useRef, useState } from "react";

interface Props { onSearch: (q: string) => void; debounceMs?: number; placeholder?: string }

export default function SearchInput({ onSearch, debounceMs = 300, placeholder = "Search..." }: Props) {
  const [value, setValue] = useState("");
  const [loading, setLoading] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const debounced = useCallback((q: string) => {
    if (timer.current) clearTimeout(timer.current);
    if (!q) { setLoading(false); onSearch(""); return; }
    setLoading(true);
    timer.current = setTimeout(() => { onSearch(q); setLoading(false); }, debounceMs);
  }, [onSearch, debounceMs]);

  useEffect(() => () => { if (timer.current) clearTimeout(timer.current); }, []);

  return (
    <div style={{ position: "relative", display: "inline-block" }}>
      <input value={value} onChange={e => { setValue(e.target.value); debounced(e.target.value); }}
        placeholder={placeholder} style={{ padding: "0.5rem 2rem 0.5rem 0.5rem" }} />
      {value && <button onClick={() => { setValue(""); onSearch(""); }}
        style={{ position: "absolute", right: "0.25rem", top: "50%", transform: "translateY(-50%)" }}>x</button>}
      {loading && <span style={{ marginLeft: "0.5rem" }}>...</span>}
    </div>
  );
}

