import React, { useState } from "react";

interface Column<T> { key: keyof T; label: string; sortable?: boolean }
interface Props<T extends { id: number }> { data: T[]; columns: Column<T>[]; pageSize?: number }

export default function DataTable<T extends { id: number }>({ data, columns, pageSize = 10 }: Props<T>) {
  const [sortKey, setSortKey] = useState<keyof T | null>(null);
  const [sortAsc, setSortAsc] = useState(true);
  const [page, setPage] = useState(0);
  const [selected, setSelected] = useState<Set<number>>(new Set());

  const sorted = [...data].sort((a, b) => {
    if (!sortKey) return 0;
    const av = a[sortKey], bv = b[sortKey];
    const cmp = String(av).localeCompare(String(bv));
    return sortAsc ? cmp : -cmp;
  });

  const paged = sorted.slice(page * pageSize, (page + 1) * pageSize);
  const totalPages = Math.ceil(data.length / pageSize);

  const toggleSort = (key: keyof T) => {
    if (sortKey === key) setSortAsc(!sortAsc);
    else { setSortKey(key); setSortAsc(true); }
  };

  const toggleRow = (id: number) => {
    setSelected(prev => { const next = new Set(prev); next.has(id) ? next.delete(id) : next.add(id); return next; });
  };

  return (
    <div>
      <table>
        <thead>
          <tr>
            <th><input type="checkbox" checked={selected.size === data.length}
              onChange={() => setSelected(selected.size === data.length ? new Set() : new Set(data.map(d => d.id)))} /></th>
            {columns.map(col => (
              <th key={String(col.key)} onClick={() => col.sortable !== false && toggleSort(col.key)}
                style={{ cursor: "pointer" }}>
                {col.label} {sortKey === col.key ? (sortAsc ? "▲" : "▼") : ""}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {paged.map(row => (
            <tr key={row.id}>
              <td><input type="checkbox" checked={selected.has(row.id)} onChange={() => toggleRow(row.id)} /></td>
              {columns.map(col => <td key={String(col.key)}>{String(row[col.key])}</td>)}
            </tr>
          ))}
        </tbody>
      </table>
      <div style={{ marginTop: "0.5rem" }}>
        <button disabled={page === 0} onClick={() => setPage(p => p - 1)}>Prev</button>
        <span> Page {page + 1}/{totalPages} </span>
        <button disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>Next</button>
        <span> ({selected.size} selected)</span>
      </div>
    </div>
  );
}

