import sqlite3
from contextlib import contextmanager
from pathlib import Path
from typing import Any, Generator


@contextmanager
def get_conn(db: Path = Path("app.db")) -> Generator[sqlite3.Connection, None, None]:
    conn = sqlite3.connect(str(db))
    conn.row_factory = sqlite3.Row
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


class UserRepository:
    def __init__(self, db: Path = Path("app.db")) -> None:
        self.db = db
        with get_conn(db) as conn:
            conn.execute("""CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email TEXT UNIQUE NOT NULL,
                name TEXT NOT NULL
            )""")

    def create(self, email: str, name: str) -> dict[str, Any]:
        with get_conn(self.db) as conn:
            cur = conn.execute("INSERT INTO users (email, name) VALUES (?, ?)", (email, name))
            return {"id": cur.lastrowid, "email": email, "name": name}

    def get(self, user_id: int) -> dict[str, Any] | None:
        with get_conn(self.db) as conn:
            row = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
            return dict(row) if row else None

    def list_all(self, limit: int = 100) -> list[dict[str, Any]]:
        with get_conn(self.db) as conn:
            return [dict(r) for r in conn.execute("SELECT * FROM users LIMIT ?", (limit,)).fetchall()]

    def update(self, user_id: int, **fields: str) -> bool:
        set_clause = ", ".join(f"{k} = ?" for k in fields)
        with get_conn(self.db) as conn:
            return conn.execute(f"UPDATE users SET {set_clause} WHERE id = ?",
                              (*fields.values(), user_id)).rowcount > 0

    def delete(self, user_id: int) -> bool:
        with get_conn(self.db) as conn:
            return conn.execute("DELETE FROM users WHERE id = ?", (user_id,)).rowcount > 0

