    text = re.sub(r"[^a-z0-9\s-]", "", text)
    return re.sub(r"[\s-]+", "-", text).strip("-")


def truncate(text: str, max_len: int = 100, suffix: str = "...") -> str:
    if len(text) <= max_len:
        return text
    return text[:max_len - len(suffix)] + suffix


def camel_to_snake(name: str) -> str:
    name = re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1_\2", name)
    name = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", name)
    return name.lower()


@pytest.mark.parametrize("text,expected", [
    ("Hello World", "hello-world"),
    ("  spaces  ", "spaces"),
    ("Special!@#Chars", "specialchars"),
])
def test_slugify(text: str, expected: str) -> None:
    assert slugify(text) == expected


@pytest.mark.parametrize("text,max_len,expected", [
    ("short", 10, "short"),
    ("a" * 15, 10, "aaaaa..."),
])
def test_truncate(text: str, max_len: int, expected: str) -> None:
    assert truncate(text, max_len) == expected


@pytest.mark.parametrize("name,expected", [
    ("camelCase", "camel_case"),
    ("PascalCase", "pascal_case"),
])
def test_camel_to_snake(name: str, expected: str) -> None:
    assert camel_to_snake(name) == expected

from __future__ import annotations

import time
import pytest


class TTLCache:
    def __init__(self) -> None:
        self._data: dict[str, tuple[str, float]] = {}

    def set(self, key: str, value: str, ttl: float = 60) -> None:
        self._data[key] = (value, time.monotonic() + ttl)

    def get(self, key: str) -> str | None:
        entry = self._data.get(key)
        if entry is None:
            return None
        value, expires = entry
        if time.monotonic() > expires:
            del self._data[key]
            return None
        return value


class TestTTLCache:
    def test_set_get(self) -> None:
        cache = TTLCache()
        cache.set("k1", "v1")
        assert cache.get("k1") == "v1"

    def test_missing_key(self) -> None:
        cache = TTLCache()
        assert cache.get("missing") is None

    def test_overwrite(self) -> None:
        cache = TTLCache()
        cache.set("k1", "v1")
        cache.set("k1", "v2")
        assert cache.get("k1") == "v2"

    def test_expiry(self) -> None:
        cache = TTLCache()
        cache.set("k1", "v1", ttl=0.01)
        time.sleep(0.02)
        assert cache.get("k1") is None

from __future__ import annotations

import json
import time
import urllib.request
import urllib.error
from typing import Any


class RestClient:
    def __init__(self, base_url: str, timeout: int = 10, retries: int = 3) -> None:
        self.base_url = base_url.rstrip("/")
        self.timeout = timeout
        self.retries = retries

    def _request(self, method: str, path: str, data: dict | None = None) -> dict[str, Any]:
        url = f"{self.base_url}{path}"
        body = json.dumps(data).encode() if data else None
        headers = {"Content-Type": "application/json"} if data else {}
        for attempt in range(1, self.retries + 1):
            try:
                req = urllib.request.Request(url, data=body, headers=headers, method=method)
                with urllib.request.urlopen(req, timeout=self.timeout) as resp:
                    return json.loads(resp.read().decode())
            except urllib.error.HTTPError as exc:
                if exc.code >= 500 and attempt < self.retries:
                    time.sleep(attempt * 0.5)
                    continue
                raise
        return {}

    def get(self, path: str) -> dict[str, Any]:
        return self._request("GET", path)

    def post(self, path: str, data: dict) -> dict[str, Any]:
        return self._request("POST", path, data)

    def put(self, path: str, data: dict) -> dict[str, Any]:
        return self._request("PUT", path, data)

    def delete(self, path: str) -> dict[str, Any]:
        return self._request("DELETE", path)

from __future__ import annotations

import queue
import threading
from concurrent.futures import Future
from typing import Any, Callable


class TaskQueue:
    def __init__(self, num_workers: int = 4) -> None:
        self._queue: queue.PriorityQueue[tuple[int, int, Future, Callable, tuple, dict]] = queue.PriorityQueue()
        self._counter = 0
        self._running = True
        self._workers = [threading.Thread(target=self._worker, daemon=True) for _ in range(num_workers)]
        for w in self._workers:
            w.start()

    def _worker(self) -> None:
        while self._running:
            try:
                _pri, _cnt, future, func, args, kwargs = self._queue.get(timeout=1)
            except queue.Empty:
                continue
            try:
                future.set_result(func(*args, **kwargs))
            except Exception as exc:
                future.set_exception(exc)

    def submit(self, func: Callable, *args: Any, priority: int = 0, **kwargs: Any) -> Future:
        fut: Future = Future()
        self._counter += 1
        self._queue.put((priority, self._counter, fut, func, args, kwargs))
        return fut

    def shutdown(self) -> None:
        self._running = False
        for w in self._workers:
            w.join(timeout=5)

from __future__ import annotations

import json
import urllib.request
from typing import Any


class GraphQLClient:
    def __init__(self, endpoint: str, headers: dict[str, str] | None = None) -> None:
        self.endpoint = endpoint
        self.headers = headers or {}

    def query(self, query: str, variables: dict | None = None) -> dict[str, Any]:
        payload: dict[str, Any] = {"query": query}
        if variables:
            payload["variables"] = variables

        data = json.dumps(payload).encode()
        headers = {"Content-Type": "application/json", **self.headers}
        req = urllib.request.Request(self.endpoint, data=data, headers=headers, method="POST")

        with urllib.request.urlopen(req, timeout=30) as resp:
            result = json.loads(resp.read().decode())

        if "errors" in result:
            raise GraphQLError(result["errors"])
        return result.get("data", {})

    def mutate(self, mutation: str, variables: dict | None = None) -> dict[str, Any]:
        return self.query(mutation, variables)


class GraphQLError(Exception):
    def __init__(self, errors: list[dict]) -> None:
        self.errors = errors
        messages = [e.get("message", "Unknown") for e in errors]
        super().__init__("GraphQL errors: " + "; ".join(messages))

