pub struct Node<T> {
    pub value: T,
    pub next: Option<Box<Node<T>>>,
}

pub struct LinkedList<T> {
    head: Option<Box<Node<T>>>,
    len: usize,
}

impl<T> LinkedList<T> {
    pub fn new() -> Self {
        LinkedList { head: None, len: 0 }
    }

    pub fn push_front(&mut self, value: T) {
        let new_node = Box::new(Node {
            value,
            next: self.head.take(),
        });
        self.head = Some(new_node);
        self.len += 1;
    }

    pub fn pop_front(&mut self) -> Option<T> {
        self.head.take().map(|node| {
            self.head = node.next;
            self.len -= 1;
            node.value
        })
    }

    pub fn is_empty(&self) -> bool {
        self.head.is_none()
    }

    pub fn len(&self) -> usize {
        self.len
    }

    pub fn iter(&self) -> LinkedListIter<T> {
        LinkedListIter { current: self.head.as_ref() }
    }
}

pub struct LinkedListIter<'a, T> {
    current: Option<&'a Box<Node<T>>>,
}

impl<'a, T> Iterator for LinkedListIter<'a, T> {
    type Item = &'a T;
    fn next(&mut self) -> Option<Self::Item> {
        self.current.take().map(|node| {
            self.current = node.next.as_ref();
            &node.value
        })
    }
}

use std::fmt;
use std::error::Error as StdError;

#[derive(Debug)]
pub enum AppError {
    NotFound(String),
    Validation(String),
    Io(std::io::Error),
}

impl fmt::Display for AppError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            AppError::NotFound(msg) => write!(f, "Not found: {}", msg),
            AppError::Validation(msg) => write!(f, "Validation error: {}", msg),
            AppError::Io(err) => write!(f, "IO error: {}", err),
        }
    }
}

impl StdError for AppError {}

impl From<std::io::Error> for AppError {
    fn from(err: std::io::Error) -> Self {
        AppError::Io(err)
    }
}

pub type AppResult<T> = Result<T, AppError>;

pub fn validate_not_empty(value: &str, field: &str) -> AppResult<()> {
    if value.trim().is_empty() {
        Err(AppError::Validation(format!("{} cannot be empty", field)))
    } else {
        Ok(())
    }
}

use std::sync::mpsc;
use std::thread;
use std::time::Duration;

pub struct TaskRunner {
    handles: Vec<thread::JoinHandle<()>>,
}

impl TaskRunner {
    pub fn new() -> Self {
        TaskRunner { handles: Vec::new() }
    }

    pub fn spawn<F>(&mut self, name: &str, f: F)
    where
        F: FnOnce() + Send + 'static,
    {
        let name = name.to_string();
        self.handles.push(thread::spawn(move || {
            println!("[{}] started", name);
            f();
            println!("[{}] finished", name);
        }));
    }

    pub fn wait_all(self) {
        for h in self.handles {
            h.join().unwrap();
        }
    }

    pub fn fan_out<F>(items: Vec<i32>, f: F) -> Vec<i32>
    where
        F: Fn(i32) -> i32 + Send + 'static,
        F: Copy,
    {
        let (tx, rx) = mpsc::channel();
        let mut handles = Vec::new();
        for item in items {
            let tx = tx.clone();
            handles.push(thread::spawn(move || {
                let result = f(item);
                tx.send(result).unwrap();
            }));
        }
        drop(tx);
        let mut results: Vec<i32> = rx.iter().collect();
        results.sort();
        results
    }
}

