package main

import (
    "encoding/json"
    "log"
    "net/http"
    "strconv"
    "strings"
    "sync"
)

type Product struct {
    ID    int     `json:"id"`
    Name  string  `json:"name"`
    Price float64 `json:"price"`
}

type Store struct {
    mu     sync.RWMutex
    items  map[int]Product
    nextID int
}

func NewStore() *Store {
    return &Store{items: make(map[int]Product), nextID: 1}
}

func (s *Store) Create(name string, price float64) Product {
    s.mu.Lock()
    defer s.mu.Unlock()
    p := Product{ID: s.nextID, Name: name, Price: price}
    s.items[p.ID] = p
    s.nextID++
    return p
}

func (s *Store) Get(id int) (Product, bool) {
    s.mu.RLock()
    defer s.mu.RUnlock()
    p, ok := s.items[id]
    return p, ok
}

func (s *Store) List() []Product {
    s.mu.RLock()
    defer s.mu.RUnlock()
    result := make([]Product, 0, len(s.items))
    for _, p := range s.items {
        result = append(result, p)
    }
    return result
}

func (s *Store) Delete(id int) bool {
    s.mu.Lock()
    defer s.mu.Unlock()
    _, ok := s.items[id]
    delete(s.items, id)
    return ok
}

var store = NewStore()

func handleProducts(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    switch r.Method {
    case http.MethodGet:
        json.NewEncoder(w).Encode(store.List())
    case http.MethodPost:
        var p Product
        if err := json.NewDecoder(r.Body).Decode(&p); err != nil {
            http.Error(w, err.Error(), http.StatusBadRequest)
            return
        }
        created := store.Create(p.Name, p.Price)
        w.WriteHeader(http.StatusCreated)
        json.NewEncoder(w).Encode(created)
    default:
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
    }
}

func handleProduct(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    parts := strings.Split(r.URL.Path, "/")
    if len(parts) < 3 {
        http.Error(w, "Bad request", http.StatusBadRequest)
        return
    }
    id, err := strconv.Atoi(parts[len(parts)-1])
    if err != nil {
        http.Error(w, "Invalid ID", http.StatusBadRequest)
        return
    }
    switch r.Method {
    case http.MethodGet:
        p, ok := store.Get(id)
        if !ok {
            http.Error(w, "Not found", http.StatusNotFound)
            return
        }
        json.NewEncoder(w).Encode(p)
    case http.MethodDelete:
        if !store.Delete(id) {
            http.Error(w, "Not found", http.StatusNotFound)
            return
        }
        w.WriteHeader(http.StatusNoContent)
    default:
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
    }
}

func main() {
    http.HandleFunc("/products", handleProducts)
    http.HandleFunc("/products/", handleProduct)
    log.Println("Server starting on :8080")
    log.Fatal(http.ListenAndServe(":8080", nil))
}

