type EventMap = Record<string, unknown>;
type EventKey<T extends EventMap> = string & keyof T;
type Handler<T> = (payload: T) => void;

export class TypedEmitter<TEvents extends EventMap> {
  private handlers = new Map<EventKey<TEvents>, Set<Handler<unknown>>>();

  on<K extends EventKey<TEvents>>(event: K, handler: Handler<TEvents[K]>): void {
    if (!this.handlers.has(event)) {
      this.handlers.set(event, new Set());
    }
    this.handlers.get(event)!.add(handler as Handler<unknown>);
  }

  off<K extends EventKey<TEvents>>(event: K, handler: Handler<TEvents[K]>): void {
    this.handlers.get(event)?.delete(handler as Handler<unknown>);
  }

  emit<K extends EventKey<TEvents>>(event: K, payload: TEvents[K]): void {
    this.handlers.get(event)?.forEach((handler) => handler(payload));
  }

  once<K extends EventKey<TEvents>>(event: K, handler: Handler<TEvents[K]>): void {
    const wrapper = (payload: TEvents[K]) => {
      handler(payload);
      this.off(event, wrapper);
    };
    this.on(event, wrapper);
  }
}

// Usage example
interface AppEvents {
  userLogin: { userId: string; timestamp: number };
  error: { message: string; code: number };
}
const emitter = new TypedEmitter<AppEvents>();
emitter.on("userLogin", (payload) => console.log(payload.userId));
